+fn sym_table_diff_coverage_report() {
+    eprintln!(
+        "{{\"family\":\"libresolv __sym_ntop + __sym_ntos + __sym_ston\",\"reference\":\"glibc-libresolv\",\"functions\":3,\"divergences\":0}}",
+    );
+}
